option.value:
.section {
  padding: 48px 0;
  background: var(--color-bg);
}

.heading {
  font-family: var(--font-display);
  font-size: clamp(26px, 3.5vw, 42px);
  letter-spacing: 0.04em;
  color: var(--color-text);
  text-align: center;
  margin-bottom: 6px;
}

.sub {
  text-align: center;
  color: var(--color-text-muted);
  font-size: 15px;
  margin-bottom: 32px;
}

.tableWrap {
  max-width: 56rem;
  margin-inline: auto;
  border-radius: var(--radius-md);
  border: 1px solid var(--color-border);
  background: var(--color-bg);
  overflow-x: auto;
  overflow-y: hidden;
  box-sizing: border-box;
  -webkit-overflow-scrolling: touch;
  scroll-behavior: smooth;
  scrollbar-width: thin;
  scrollbar-color: var(--color-border) transparent;
}

/* Inner wrapper for centered padding */
.tableInner {
  display: inline-block;
  min-width: 100%;
  padding: 1.5rem;
  box-sizing: border-box;
  margin: 0 auto;
}

/* Webkit browsers scrollbar styling */
.tableWrap::-webkit-scrollbar {
  height: 6px;
}

.tableWrap::-webkit-scrollbar-track {
  background: transparent;
}

.tableWrap::-webkit-scrollbar-thumb {
  background-color: var(--color-border);
  border-radius: 3px;
  border: 2px solid transparent;
  background-clip: content-box;
}

.tableWrap::-webkit-scrollbar-thumb:hover {
  background-color: var(--color-text-muted);
  background-clip: content-box;
}

.table {
  width: 100%;
  min-width: 560px;
  border-collapse: collapse;
}

.thEmpty { width: 36%; }

.thEarasers,
.th {
  padding: 12px 16px;
  text-align: center;
  font-size: 13px;
  font-weight: 600;
  letter-spacing: 0.04em;
  border-bottom: 1px solid var(--color-border);
}

.th {
  color: var(--color-text-muted);
  background: var(--color-surface);
}

.thEarasers {
  background: rgba(240,120,120,0.08);
  border-left: 2px solid var(--color-accent);
  border-right: 2px solid var(--color-accent);
}

.thBadge {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  color: var(--color-accent);
  font-size: 15px;
}

.row { transition: background 0.15s; }
.row:hover { background: var(--color-surface-2); }

.tdLabel {
  padding: 10px 16px;
  font-size: 13px;
  color: var(--color-text-muted);
  border-bottom: 1px solid var(--color-border);
  background: var(--color-surface);
}

.row:last-child .tdLabel,
.row:last-child .td,
.row:last-child .tdEarasers {
  border-bottom: none;
}

.td {
  padding: 10px 16px;
  text-align: center;
  font-size: 13px;
  color: var(--color-text-muted);
  border-bottom: 1px solid var(--color-border);
  background: var(--color-surface);
}

.tdEarasers {
  composes: td;
  background: rgba(240,120,120,0.05);
  border-left: 2px solid var(--color-accent);
  border-right: 2px solid var(--color-accent);
  color: var(--color-text);
  font-weight: 500;
}

.yes { color: var(--color-success); display: flex; justify-content: center; align-items: center; }
.no  { color: var(--color-danger);  display: flex; justify-content: center; align-items: center; }

.cta {
  text-align: center;
  margin-top: 40px;
}

.ctaBtn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 14px 32px;
  background: var(--color-accent);
  color: var(--color-bg);
  font-size: 14px;
  font-weight: 600;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  border-radius: var(--radius-sm);
  transition: opacity 0.2s, transform 0.2s;
}

.ctaBtn:hover {
  opacity: 0.88;
  transform: translateY(-2px);
}

@media (max-width: 700px) {
  .tableWrap {
    border-radius: 0;
    border-left: none;
    border-right: none;
    margin-left: calc(-50vw + 50%);
    margin-right: calc(-50vw + 50%);
  }
  .tableInner {
    padding: 1rem;
  }
  .table {
    min-width: 420px;
  }
}

